import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Course } from '../../core/models';

/**
 * LearnLoop instructor dashboard — list / create / edit / delete courses.
 * Loads via ApiService.listCourses() in ngOnInit(). Create/edit uses an inline
 * form; delete calls ApiService.deleteCourse().
 */
@Component({
  selector: 'app-instructor-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './instructor-dashboard.component.html',
  styleUrl: './instructor-dashboard.component.css',
})
export class InstructorDashboardComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  readonly courses = signal<Course[]>([
    {
      id: 'c1',
      title: 'Intro to Web Development',
      description: 'HTML, CSS, and the fundamentals of the browser.',
      moduleCount: 2,
      lessonCount: 3,
      quizCount: 1,
    },
    {
      id: 'c2',
      title: 'JavaScript Foundations',
      description: 'Variables, functions, and control flow.',
      moduleCount: 3,
      lessonCount: 8,
      quizCount: 2,
    },
  ]);

  // Inline create/edit form state.
  readonly showForm = signal(false);
  editingId: string | null = null;
  formTitle = '';
  formDescription = '';

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.listCourses().subscribe({
      next: (courses) => {
        this.courses.set(courses);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load courses. Please try again.');
        this.loading.set(false);
      },
    });
  }

  openCreate(): void {
    this.editingId = null;
    this.formTitle = '';
    this.formDescription = '';
    this.showForm.set(true);
  }

  openEdit(course: Course): void {
    this.editingId = course.id;
    this.formTitle = course.title;
    this.formDescription = course.description;
    this.showForm.set(true);
  }

  cancel(): void {
    this.showForm.set(false);
  }

  save(): void {
    if (!this.formTitle.trim()) return;
    const body = { title: this.formTitle.trim(), description: this.formDescription.trim() };
    if (this.editingId) {
      const id = this.editingId;
      this.api.updateCourse(id, body).subscribe({
        next: () =>
          this.courses.update((cs) => cs.map((c) => (c.id === id ? { ...c, ...body } : c))),
      });
    } else {
      this.api.createCourse(body).subscribe({
        next: (created) => this.courses.update((cs) => [...cs, created]),
      });
      // Optimistic local add for the mockup.
      this.courses.update((cs) => [
        ...cs,
        { id: 'new-' + cs.length, ...body, moduleCount: 0, lessonCount: 0, quizCount: 0 },
      ]);
    }
    this.showForm.set(false);
  }

  remove(course: Course): void {
    this.api.deleteCourse(course.id).subscribe({ error: () => {} });
    this.courses.update((cs) => cs.filter((c) => c.id !== course.id));
  }
}
